import Foundation

class AnalyticsDebugger {
    static let shared = AnalyticsDebugger()
    
    private init() {}
    
    // Log user authentication flow
    func logAuthentication(userId: String, email: String, token: String?) {
        NSLog("User Authentication: userId=\(userId), email=\(email), token=\(String(describing: token))")
        print("User Authentication: userId=\(userId), email=\(email), token=\(String(describing: token))")
    }
    
    // Log API calls with request and response details
    func logAPICall(endpoint: String, requestPayload: [String: Any], response: URLResponse?, data: Data?, error: Error?) {
        let requestString = String(data: try! JSONSerialization.data(withJSONObject: requestPayload), encoding: .utf8) ?? "Invalid Request"
        let responseString = data != nil ? String(data: data!, encoding: .utf8) ?? "Invalid Response" : "No Response"
        
        NSLog("API Call: endpoint=\(endpoint), request=\(requestString), response=\(responseString), error=\(String(describing: error))")
        print("API Call: endpoint=\(endpoint), request=\(requestString), response=\(responseString), error=\(String(describing: error))")
    }
    
    // Log user data changes
    func logUserDataChange(userId: String, email: String, changes: [String: Any]) {
        let changesString = changes.map { "\($0.key)=\($0.value)" }.joined(separator: ", ")
        
        NSLog("User Data Change: userId=\(userId), email=\(email), changes=[\(changesString)]")
        print("User Data Change: userId=\(userId), email=\(email), changes=[\(changesString)]")
    }
    
    // Log error conditions
    func logErrorCondition(userId: String?, email: String?, error: Error, context: String) {
        NSLog("Error Condition: userId=\(String(describing: userId)), email=\(String(describing: email)), error=\(error.localizedDescription), context=\(context)")
        print("Error Condition: userId=\(String(describing: userId)), email=\(String(describing: email)), error=\(error.localizedDescription), context=\(context)")
    }
